import uuid

@pytest.fixture
def unique_email():
    return f"test-{uuid.uuid4()}@example.com"

def test_user_registration(client, unique_email):
    response = client.post("/api/users", json={"email": unique_email})
    assert response.status_code == 201

# conftest.py import pytest from sqlalchemy import create_engine from sqlalchemy.orm import sessionmaker from testcontainers.postgres import PostgresContainer from app.models import Base
@pytest.fixture(scope="session") def postgres_container(): with PostgresContainer("postgres:16-alpine") as postgres: yield postgres
@pytest.fixture(scope="session") def engine(postgres_container): engine = create_engine(postgres_container.get_connection_url()) Base.metadata.create_all(engine) return engine
@pytest.fixture def session(engine): connection = engine.connect() transaction = connection.begin() db = sessionmaker(bind=connection)() yield db db.close() transaction.rollback() connection.close()

@pytest.mark.django_db
def test_create_user():
    user = User.objects.create(email="test@example.com")
    assert user.pk is not None

@pytest.mark.django_db(transaction=True)
def test_unique_email_constraint():
    User.objects.create(email="dup@example.com")
    with pytest.raises(IntegrityError):
        User.objects.create(email="dup@example.com")

import factory
from factory.django import DjangoModelFactory

class UserFactory(DjangoModelFactory):
    class Meta:
        model = User

    email = factory.Sequence(lambda n: f"user{n}@example.com")
    name = factory.Faker("name")
    is_active = True

@pytest.fixture
def user(db):
    return UserFactory()

@pytest.fixture
def admin_user(db):
    return UserFactory(is_staff=True, is_superuser=True)

from fastapi.testclient import TestClient

@pytest.fixture
def client(session):
    def override_get_db():
        yield session

    app.dependency_overrides[get_db] = override_get_db
    with TestClient(app) as c:
        yield c
    app.dependency_overrides.clear()

def test_create_user(client):
    response = client.post("/api/users", json={
        "email": "new@example.com",
        "name": "New User",
    })
    assert response.status_code == 201
    assert response.json()["email"] == "new@example.com"

def test_get_nonexistent_user(client):
    response = client.get("/api/users/nonexistent-id")
    assert response.status_code == 404

import pytest from httpx import ASGITransport, AsyncClient
@pytest.fixture async def async_client(session): app.dependency_overrides[get_db] = lambda: session async with AsyncClient( transport=ASGITransport(app=app), base_url="http://test", ) as client: yield client app.dependency_overrides.clear()
@pytest.mark.anyio async def test_list_users(async_client): response = await async_client.get("/api/users") assert response.status_code == 200 assert isinstance(response.json(), list)

import respx from httpx import Response
@respx.mock async def test_fetch_user_from_external_api(): respx.get("https://api.example.com/users/1").mock( return_value=Response(200, json={"id": 1, "name": "Test User"}) )
result = await fetch_user(user_id=1)
assert result["name"] == "Test User" assert respx.calls.call_count == 1
@respx.mock async def test_handles_external_api_error(): respx.get("https://api.example.com/users/99").mock( return_value=Response(404) )
with pytest.raises(UserNotFoundError): await fetch_user(user_id=99)

import requests
from testcontainers.core.container import DockerContainer

@pytest.fixture(scope="session")
def wiremock_url():
    container = DockerContainer("wiremock/wiremock:3.3.1")
    container.with_exposed_ports(8080)
    container.start()
    url = f"http://{container.get_container_host_ip()}:{container.get_exposed_port(8080)}"
    yield url
    container.stop()

@pytest.fixture(autouse=True)
def clear_wiremock_mappings(wiremock_url):
    yield
    requests.delete(f"{wiremock_url}/__admin/mappings")

def stub_payment_success(wiremock_url: str):
    requests.post(f"{wiremock_url}/__admin/mappings", json={
        "request": {"method": "POST", "urlPath": "/charge"},
        "response": {
            "status": 200,
            "jsonBody": {"payment_id": "pay_123", "status": "success"},
        },
    })

def test_payment_flow(client, wiremock_url):
    stub_payment_success(wiremock_url)
    response = client.post("/api/orders/1/pay")
    assert response.status_code == 200
